import{_ as o,C as r,o as l,c as a,j as e,E as i,a as n,a3 as c}from"./chunks/framework.BTFg6ESq.js";const k=JSON.parse('{"title":"请求设置","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/tools/llm-chat/settings/request.md","filePath":"user-guide/tools/llm-chat/settings/request.md","lastUpdated":1778239080000}'),u={name:"user-guide/tools/llm-chat/settings/request.md"},d={id:"请求设置",tabindex:"-1"};function g(m,t,p,_,h,b){const s=r("LIcon");return l(),a("div",null,[e("h1",d,[i(s,{name:"Globe",size:"28"}),t[0]||(t[0]=n(" 请求设置 ",-1)),t[1]||(t[1]=e("a",{class:"header-anchor",href:"#请求设置","aria-label":'Permalink to "<LIcon name="Globe" size="28" /> 请求设置"'},"​",-1))]),t[2]||(t[2]=c('<p>请求设置模块负责优化与大模型后端通信的稳定性，并确保你的对话数据在任何意外情况下都能安全保存。</p><h2 id="网络稳定性-network-stability" tabindex="-1">网络稳定性 (Network Stability) <a class="header-anchor" href="#网络稳定性-network-stability" aria-label="Permalink to &quot;网络稳定性 (Network Stability)&quot;">​</a></h2><ul><li><strong>超时管理</strong>: <ul><li><strong>请求超时</strong>: 设置单次请求的最长等待时间（默认 60s）。对于推理速度较慢的长文本模型，建议适当调大。</li></ul></li><li><strong>智能重试策略</strong>: <ul><li><strong>重试模式</strong>: <ul><li><strong>固定间隔</strong>: 简单的重复尝试。</li><li><strong>指数退避 (推荐)</strong>: 失败后等待时间翻倍。这能有效规避 API 服务商的并发限制（Rate Limit），是专业用户的首选。</li></ul></li><li><strong>最大重试次数</strong>: 建议设为 3-5 次，以平衡响应速度和连接成功率。</li></ul></li></ul><h2 id="数据安全与持久化-persistence" tabindex="-1">数据安全与持久化 (Persistence) <a class="header-anchor" href="#数据安全与持久化-persistence" aria-label="Permalink to &quot;数据安全与持久化 (Persistence)&quot;">​</a></h2><ul><li><strong>增量自动保存 (Incremental Save)</strong>: <ul><li><strong>核心功能</strong>: 在模型生成长文本的过程中，系统会以设定的频率（如每 2000ms）在后台静默保存已生成的片段。</li><li><strong>应用场景</strong>: 即使在生成过程中应用突然崩溃、电脑断电或网络彻底中断，当你重新打开应用时，已经生成的那部分内容也会被完整保留，无需重新生成。</li></ul></li><li><strong>保存间隔</strong>: 建议根据电脑性能设置。较短的间隔提供更高的数据安全性，但会增加磁盘 I/O 频率。</li></ul><hr><div class="tip custom-block"><p class="custom-block-title">提示</p><p>如果你正在使用不稳定的代理服务器或进行超长文本生成，请务必开启 <strong>“生成中自动保存”</strong>。</p></div>',7))])}const P=o(u,[["render",g]]);export{k as __pageData,P as default};
